  1	import * as React from 'react';
  2	import { CopyToClipboard } from '@odf/shared/utils/copy-to-clipboard';
  3	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
  4	import { Base64 } from 'js-base64';
  5	import {
  6	  Button,
  7	  DescriptionList,
  8	  DescriptionListDescription,
  9	  DescriptionListGroup,
 10	  DescriptionListTerm,
 11	} from '@patternfly/react-core';
 12	import { EyeSlashIcon, EyeIcon } from '@patternfly/react-icons';
 13	import { EmptyBox } from '../generic/status-box';
 14	import { SectionHeading } from '../heading/page-heading';
 15	import { ConfigMapModel, SecretModel } from '../models';
 16	import { getName, getNamespace } from '../selectors';
 17	import { ConfigMapKind, K8sResourceKind, SecretKind } from '../types';
 18	import { useCustomTranslation } from '../useCustomTranslationHook';
 19	import '../style.scss';
 20	
 21	type SecretValueProps = {
 22	  value: string;
 23	  encoded?: boolean;
 24	  reveal: boolean;
 25	};
 26	
 27	export const MaskedData: React.FC<{}> = () => {
 28	  const { t } = useCustomTranslation();
 29	  return (
 30	    <>
 31	      <span className="sr-only">{t('Value hidden')}</span>
 32	      <span aria-hidden="true">&bull;&bull;&bull;&bull;&bull;</span>
 33	    </>
 34	  );
 35	};
 36	
 37	export const SecretValue: React.FC<SecretValueProps> = ({
 38	  value,
 39	  reveal,
 40	  encoded = true,
 41	}) => {
 42	  const { t } = useCustomTranslation();
 43	  if (!value) {
 44	    return <span className="text-muted">{t('No value')}</span>;
 45	  }
 46	
 47	  const decodedValue = encoded ? Base64.decode(value) : value;
 48	  const visibleValue = reveal ? decodedValue : <MaskedData />;
 49	  return <CopyToClipboard value={decodedValue} visibleValue={visibleValue} />;
 50	};
 51	
 52	export const GetSecret: React.FC<GetSecretProps> = ({ obj }) => {
 53	  const { t } = useCustomTranslation();
 54	  const [reveal, setReveal] = React.useState(false);
 55	
 56	  const name = getName(obj);
 57	  const namespace = getNamespace(obj);
 58	
 59	  const [secretResource, cmResource] = React.useMemo(
 60	    () => [
 61	      {
 62	        kind: SecretModel.kind,
 63	        namespace,
 64	        name,
 65	        isList: false,
 66	      },
 67	      {
 68	        kind: ConfigMapModel.kind,
 69	        namespace,
 70	        name,
 71	        isList: false,
 72	      },
 73	    ],
 74	    [name, namespace]
 75	  );
 76	
 77	  const [secretData, secretLoaded, secretLoadError] =
 78	    useK8sWatchResource<SecretKind>(secretResource);
 79	
 80	  const [configData, configLoaded, configLoadError] =
 81	    useK8sWatchResource<ConfigMapKind>(cmResource);
 82	  const isLoaded = secretLoaded && configLoaded;
 83	  const error = secretLoadError || configLoadError;
 84	  const bucketName = configData?.data?.BUCKET_NAME;
 85	  const endpoint = `${configData?.data?.BUCKET_HOST}:${configData?.data?.BUCKET_PORT}`;
 86	  const accessKey =
 87	    isLoaded && !error
 88	      ? Base64.decode(secretData?.data?.AWS_ACCESS_KEY_ID)
 89	      : '';
 90	  const secretKey =
 91	    isLoaded && !error
 92	      ? Base64.decode(secretData?.data?.AWS_SECRET_ACCESS_KEY)
 93	      : '';
 94	
 95	  const secretValues =
 96	    isLoaded && !error
 97	      ? [
 98	          { field: 'Endpoint', value: endpoint },
 99	          { field: 'Bucket Name', value: bucketName },
100	          { field: 'Access Key', value: accessKey },
101	          { field: 'Secret Key', value: secretKey },
102	        ]
103	      : [];
104	
105	  const dl = secretValues.length
106	    ? secretValues.reduce((acc, datum) => {
107	        const { field, value } = datum;
108	        acc.push(
109	          <DescriptionListGroup>
110	            <DescriptionListTerm key={`${field}-k`} data-test="secret-data">
111	              {field}
112	            </DescriptionListTerm>
113	            <DescriptionListDescription key={`${field}-v`}>
114	              <SecretValue value={value} reveal={reveal} encoded={false} />
115	            </DescriptionListDescription>
116	          </DescriptionListGroup>
117	        );
118	
119	        return acc;
120	      }, [])
121	    : [];
122	
123	  return dl.length ? (
124	    <div className="odf-m-pane__body">
125	      <SectionHeading text={t('Object Bucket Claim Data')}>
126	        {secretValues.length ? (
127	          <Button
128	            type="button"
129	            onClick={() => setReveal(!reveal)}
130	            variant="link"
131	            className="pf-m-link--align-right"
132	          >
133	            {reveal ? (
134	              <>
135	                <EyeSlashIcon className="co-icon-space-r" />
136	                {t('Hide Values')}
137	              </>
138	            ) : (
139	              <>
140	                <EyeIcon className="co-icon-space-r" />
141	                {t('Reveal Values')}
142	              </>
143	            )}
144	          </Button>
145	        ) : null}
146	      </SectionHeading>
147	      {dl.length ? (
148	        <DescriptionList className="secret-data">{dl}</DescriptionList>
149	      ) : (
150	        <EmptyBox label={t('Data')} />
151	      )}
152	    </div>
153	  ) : null;
154	};
155	
156	type GetSecretProps = {
157	  obj: K8sResourceKind;
158	};

